/// <summary>
/// Creates ROW_Number expression with the Over clause
/// </summary>
/// <param name="_partitionBy">
/// the list of fields to partition the output
/// </param>
/// <param name="_orderBy">
/// the list of fields to order inside the parition
/// </param>
/// <returns>
/// A String that contains an expression for a row number over a specified partition
/// </returns>
public static client server str DBMDBRowNumOverOrderBy(List _partitionBy, List _orderBy = null)
{
    str retVal ='ROW_NUMBER()';
    ListEnumerator le = _partitionBy.getEnumerator();
    boolean partitionByIsInitialized;
    boolean orderByIsInitialized;
    SortOrder sortOrder;
    Str fldName;
    str orderString;
    while (le.moveNext())
    {
        if (!partitionByIsInitialized)
        {
            retVal += strFmt('OVER(PARTITION BY %1',le.current());
            partitionByIsInitialized = true;
        }
        else
        {
            retVal += strFmt(', %1',le.current());
        }

    }
    if (!prmIsDefault(_orderBy))
    {
        le = _orderBy.getEnumerator();
        while (le.moveNext())
        {
            [fldName,sortOrder] = le.current();
            orderString = (sortOrder==SortOrder::Ascending)?'ASC':'DESC';
            if (!orderByIsInitialized)
            {
                retVal += strFmt(' ORDER BY %1 %2',fldName,orderString);
                orderByIsInitialized = true;
            }
            else
            {
                retVal += strFmt(', %1 %2',fldName,orderString);
            }
        }

    }
    retVal +=' )';
    return retVal;

}

/// <summary>
/// Rounds datetime to a specified number of the time units
/// </summary>
/// <param name="_fieldName">
/// A String value that contains the return date field
/// </param>
/// <param name="_rounding">
/// A reference to a field or literal with an integet number of time units
/// </param>
/// <param name="_datepart">
/// A string with the timeunit (see https://learn.microsoft.com/en-us/sql/t-sql/functions/date-bucket-transact-sql?view=sql-server-ver16 )
/// </param>
/// <returns>
/// A String that contains an expression formatted as a dateOfWeek expression
/// </returns>
public static client server str DBMDBDateBucket(str _fieldName, str _rounding, str _datepart)
{
    if (false) //DBMSQLUtils::databaseCompatibilityLevel() >= 160) //to be uncommented after CHE's local SQL Server is upgraded to SQL 2022
    {
        return strFmt('DATE_BUCKET(%1,%2,%3)',_datepart,_rounding, _fieldName);
    }
    else
    {
        return strFmt('dateadd(%1, datediff(%1,0,%3) / %2 * %2, 0)',_datepart,_rounding, _fieldName);
    }
}

/// <summary>
/// Rounds datetime to a specified number of the time units
/// </summary>
/// <param name="_expressionEndDateTime">
/// A String value that contains the end date time for the duration
/// </param>
/// <param name="_expressionStartDateTime">
/// A String value that contains the start date time for the duration
/// </param>
/// <returns>
/// A String that contains an expression with the duration as a string
/// </returns>
public static client server str DBMDBDurationAsString(str _expressionEndDateTime, str _expressionStartDateTime)
{
    return strFmt('iif(CONVERT(int,DATEDIFF(DAY, %1, %2))<24850,CONVERT(varchar, DATEADD(SECOND, DATEDIFF(SECOND, %1, %2), 0), 108),CONVERT(varchar, DATEADD(SECOND, 0, 0), 108))',_expressionStartDateTime,_expressionEndDateTime);
}
